function useTheme() {
  const [themeColor, setThemeColor] = useState(localStorage.getItem('themeColor') || '#8b9ced');
  useEffect(() => { localStorage.setItem('themeColor', themeColor); }, [themeColor]);
  return [themeColor, setThemeColor];
}

export default function App() {
  const [user, loading] = useAuthState(auth);
  const [themeColor, setThemeColor] = useTheme();
  const [showAuth, setShowAuth] = useState(false);

  const userRef = user ? firestore.collection('users').doc(user.uid) : null;
  const [userDoc] = useDocumentData(userRef);

  useEffect(() => {
    if (!user) return;
    if (userDoc && userDoc.banned) return;
    const ping = () => {
      if (userRef) {
        userRef.set({ uid: user.uid, email: user.email || '', displayName: user.displayName || (user.email ? user.email.split('@')[0] : 'Anonymous'), photoURL: user.photoURL || DEFAULT_AVATAR, lastActive: Date.now() }, { merge: true });
      }
    };
    ping(); 
    const int = setInterval(ping, 180000); 
    return () => clearInterval(int);
  }, [user, userDoc, userRef]);

  if (loading) return <div style={{background: '#36393f', height: '100%'}}></div>;
  
  if (userDoc && userDoc.banned) {
    return <div className="signin-container" style={{flexDirection: 'column', color: 'white'}}><h1 style={{color: '#ed4245'}}>Banned</h1><button className="sign-in" onClick={() => auth.signOut()}>Log Out</button></div>;
  }
  
  if (showAuth && !user) return <AuthScreen themeColor={themeColor} goBack={() => setShowAuth(false)} />;

  return <MainApp themeColor={themeColor} setThemeColor={setThemeColor} isGuest={!user} onLoginClick={() => setShowAuth(true)} />;
}

function AuthScreen({ themeColor, goBack }) {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState(''); 
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleAuth = async (e) => {
    e.preventDefault();
    setError('');
    try { 
      if (isLogin) {
        await auth.signInWithEmailAndPassword(email, password);
      } else {
        await auth.createUserWithEmailAndPassword(email, password);
      }
    } 
    catch (err) { setError(err.message); }
  };
  
  return (
    <div className="signin-container">
      <div className="modal-box" style={{width: '320px', alignItems: 'center'}}>
        <button onClick={goBack} style={{position:'absolute', top:10, left:10, background:'none', color:'#8e9297', fontSize:20}}>←</button>
        <img src={DEFAULT_AVATAR} alt="logo" style={{width: 60}} />
        <h2 style={{margin: 0, color: '#fff'}}>{isLogin ? 'Welcome Back' : 'Create Account'}</h2>
        <form onSubmit={handleAuth} style={{display:'flex', flexDirection:'column', gap:16, width:'100%', padding:0, background:'none'}}>
          <input type="email" placeholder="Email" value={email} onChange={e=>setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={e=>setPassword(e.target.value)} required />
          <button type="submit" className="sign-in" style={{background: themeColor}}>{isLogin ? 'Login' : 'Sign Up'}</button>
        </form>
        {error && <p style={{color: '#ed4245', fontSize: '13px', textAlign: 'center'}}>{error}</p>}
        <p style={{color: themeColor, fontSize: 13, cursor: 'pointer', margin:0}} onClick={() => setIsLogin(!isLogin)}>{isLogin ? 'Need an account?' : 'Have an account? Login'}</p>
        <button className="sign-in" style={{width:'100%', background:'#fff', color:'#000'}} onClick={() => auth.signInWithPopup(new firebase.auth.GoogleAuthProvider())}>Google Login</button>
      </div>
    </div>
  );
}

