function MainApp({ themeColor, setThemeColor, isGuest, onLoginClick }) {
  const [view, setView] = useState('servers');
  const [currentServer, setCurrentServer] = useState(null);
  const [currentChannel, setCurrentChannel] = useState(null);
  const [activeDM, setActiveDM] = useState(null);
  
  const [showSettings, setShowSettings] = useState(false);
  const [editingServer, setEditingServer] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);
  const [mobileNav, setMobileNav] = useState(false);

  const isAdmin = !isGuest && auth.currentUser && auth.currentUser.email === 'vincentr111222@gmail.com';
  
  const [allServers] = useCollectionData(firestore.collection('servers').orderBy('createdAt'), { idField: 'id' });
  const [allUsers] = useCollectionData(firestore.collection('users'));
  
  const dmsQuery = !isGuest && auth.currentUser ? firestore.collection('dms').where('users', 'array-contains', auth.currentUser.uid) : null;
  const [allDMs] = useCollectionData(dmsQuery, { idField: 'id' });

  let servers = [];
  if (allServers) {
    servers = allServers.filter(s => {
      if (isAdmin) return true;
      if (!s.isPrivate) return true;
      if (!isGuest && s.members && auth.currentUser && s.members.includes(auth.currentUser.uid)) return true;
      return false;
    });
  }

  let currentUserData = null;
  if (allUsers && auth.currentUser) {
    currentUserData = allUsers.find(u => u.uid === auth.currentUser.uid);
  }

  useEffect(() => { 
    if (servers.length > 0 && !currentServer && view === 'servers') {
      setCurrentServer(servers[0]); 
    }
  }, [servers, currentServer, view]);

  const startDM = async (targetUser) => {
    if (!auth.currentUser) return;
    const uid1 = auth.currentUser.uid; 
    const uid2 = targetUser.uid;
    const dmId = uid1 < uid2 ? `${uid1}_${uid2}` : `${uid2}_${uid1}`;
    const dmRef = firestore.collection('dms').doc(dmId);
    const doc = await dmRef.get();
    if (!doc.exists) {
      await dmRef.set({ users: [uid1, uid2], updatedAt: firebase.firestore.FieldValue.serverTimestamp() });
    }
    setView('dms'); 
    setActiveDM({ id: dmId, target: targetUser });
  };

  return (
    <div className="discord-layout">
      {isGuest && <div style={{position:'absolute', top:0, left:0, right:0, background:'#faa61a', color:'#000', textAlign:'center', fontSize:12, fontWeight:'bold', padding:4, zIndex:1000}}>Guest Mode — Read Only.</div>}
      
      {showSettings && !isGuest && <SettingsModal close={()=>setShowSettings(false)} theme={themeColor} setTheme={setThemeColor} isAdmin={isAdmin} userDoc={currentUserData} />}
      {editingServer && !isGuest && <ServerSettingsModal server={editingServer} close={()=>setEditingServer(null)} theme={themeColor} />}
      <ProfileModal userProfile={selectedUser} close={()=>setSelectedUser(null)} themeColor={themeColor} isGuest={isGuest} onLoginClick={onLoginClick} startDM={startDM} isSelf={selectedUser && auth.currentUser && selectedUser.uid === auth.currentUser.uid} />
      
      {mobileNav && <div className="mobile-overlay open" onClick={() => setMobileNav(false)}></div>}

      <div className="sidebar" style={{paddingTop: isGuest ? 30 : 12}}>
        <div className={`server-icon ${view === 'dms' ? 'active' : ''}`} onClick={() => { setView('dms'); setMobileNav(true); }} style={{background: 'transparent'}}>
           <img src={DEFAULT_AVATAR} alt="DM" style={{width: 48, height: 48, borderRadius: view==='dms'?16:24, transition: '0.3s'}} />
        </div>
        <div className="divider"></div>
        {servers.map(s => (
          <div key={s.id} className={`server-icon ${currentServer && currentServer.id === s.id && view === 'servers' ? 'active' : ''}`} style={s.icon && s.icon.startsWith('data:') ? {backgroundImage: `url(${s.icon})`} : {}} onClick={() => { setView('servers'); setCurrentServer(s); setCurrentChannel(null); setMobileNav(true); }}>
            {(!s.icon || !s.icon.startsWith('data:')) ? (s.icon || s.name.charAt(0).toUpperCase()) : ''}
            {isAdmin && <div className="server-actions">
              <button className="action-btn edit-btn" onClick={(e) => { e.stopPropagation(); setEditingServer(s); }}>✎</button>
              <button className="action-btn del-btn-server" onClick={async (e) => { e.stopPropagation(); if(window.confirm("Delete server?")) await firestore.collection('servers').doc(s.id).delete(); }}>✕</button>
            </div>}
          </div>
        ))}
        {isAdmin && <div className="server-icon server-add-btn" onClick={async () => { const n = prompt("Server Name:"); if(n) await firestore.collection('servers').add({ name: n, icon: n.charAt(0).toUpperCase(), isPrivate: false, createdAt: firebase.firestore.FieldValue.serverTimestamp() }); }}>+</div>}
        {!isAdmin && !isGuest && <div className="server-icon server-join-btn" onClick={async () => {
          const c = prompt("Enter 6-digit Code:"); 
          if(!c) return;
          const match = allServers.find(s => s.inviteCode === c.toUpperCase());
          if(match) { 
            await firestore.collection('servers').doc(match.id).update({ members: firebase.firestore.FieldValue.arrayUnion(auth.currentUser.uid) }); 
            alert("Joined!"); 
          } else {
             alert("Invalid code.");
          }
        }}>Join</div>}
      </div>

      {view === 'servers' && currentServer ? (
        <ServerContent server={currentServer} channel={currentChannel} setChannel={setCurrentChannel} isAdmin={isAdmin} isGuest={isGuest} theme={themeColor} onLoginClick={onLoginClick} mobileNav={mobileNav} setMobileNav={setMobileNav} allUsers={allUsers} openProfile={setSelectedUser} myData={currentUserData} openSettings={()=>setShowSettings(true)} />
      ) : view === 'dms' && !isGuest ? (
        <DMContent dms={allDMs} activeDM={activeDM} setActiveDM={setActiveDM} allUsers={allUsers} theme={themeColor} mobileNav={mobileNav} setMobileNav={setMobileNav} myData={currentUserData} openSettings={()=>setShowSettings(true)} openProfile={setSelectedUser} />
      ) : (
        <div style={{flex:1, display:'flex', justifyContent:'center', alignItems:'center'}}><h3 style={{color:'#8e9297'}}>{isGuest ? 'Log in to use Direct Messages' : 'Select a server or DM'}</h3></div>
      )}
    </div>
  );
}

function ServerContent({ server, channel, setChannel, isAdmin, isGuest, theme, onLoginClick, mobileNav, setMobileNav, allUsers, openProfile, myData, openSettings }) {
  const dummy = useRef();
  const [form, setForm] = useState(''); 
  const [file, setFile] = useState(null);
  const [showMembers, setShowMembers] = useState(false);

  const channelsRef = firestore.collection(`servers/${server.id}/channels`);
  const [channels] = useCollectionData(channelsRef.orderBy('createdAt'), { idField: 'id' });
  const msgsRef = channel ? firestore.collection(`servers/${server.id}/channels/${channel.id}/messages`) : null;
  const [messages] = useCollectionData(msgsRef ? msgsRef.orderBy('createdAt').limit(50) : null, { idField: 'id' });

  useEffect(() => { 
    if (channels && channels.length > 0 && !channel) {
      setChannel(channels[0]); 
    }
  }, [channels, channel, setChannel]);

  const sendMsg = async (e) => {
    e.preventDefault(); 
    if(isGuest) return onLoginClick();
    if (!form.trim() && !file) return;
    if (msgsRef && auth.currentUser) {
      await msgsRef.add({ text: form, fileData: file ? file.data : null, fileType: file ? file.type : null, fileName: file ? file.name : null, createdAt: firebase.firestore.FieldValue.serverTimestamp(), uid: auth.currentUser.uid, photoURL: myData ? myData.photoURL : DEFAULT_AVATAR, displayName: myData ? myData.displayName : 'User' });
    }
    setForm(''); 
    setFile(null); 
    if (dummy.current) {
      dummy.current.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleFile = (e) => {
    if(isGuest) return onLoginClick();
    const f = e.target.files[0]; 
    if(!f) return;
    if(f.size > 500000) return alert("File too large. Max 500KB.");
    const reader = new FileReader();
    reader.onload = (ev) => {
      if(f.type.startsWith('image/')) {
        const img = new Image(); 
        img.onload = () => {
          const cvs = document.createElement('canvas'); 
          let w = img.width, h = img.height; 
          if(w>800){ h*=800/w; w=800; } 
          cvs.width=w; 
          cvs.height=h; 
          cvs.getContext('2d').drawImage(img,0,0,w,h);
          setFile({ data: cvs.toDataURL(f.type, 0.7), type: 'image', name: f.name });
        }; 
        img.src = ev.target.result;
      } else {
         setFile({ data: ev.target.result, type: 'file', name: f.name });
      }
    }; 
    reader.readAsDataURL(f);
  };

  let members = [];
  if (allUsers) {
    members = allUsers.filter(u => {
      if (u.banned) return false;
      if (isAdmin) return true;
      if (!server.isPrivate) return true;
      if (server.members && server.members.includes(u.uid)) return true;
      return false;
    });
  }

  return (
    <>
      <div className={`channels ${mobileNav ? 'open' : ''}`}>
        <div className="channels-header">
          <h3>{server.name}</h3>
          {isAdmin && <button className="add-btn" onClick={async()=>{const n=prompt("Channel Name:"); if(n) await channelsRef.add({name: n.toLowerCase(), createdAt: firebase.firestore.FieldValue.serverTimestamp()})}}>+</button>}
        </div>
        <div className="channel-list">
          {channels && channels.map(c => (
            <div key={c.id} className={`channel ${channel && channel.id===c.id ? 'active':''}`} onClick={()=>{setChannel(c); setMobileNav(false);}}>
              <span className="channel-name"><span className="hash-icon">#</span> {c.name}</span>
              {isAdmin && <button className="del-btn" onClick={async(e)=>{e.stopPropagation(); if(window.confirm("Delete?")) await channelsRef.doc(c.id).delete();}}>✕</button>}
            </div>
          ))}
        </div>
        <div className="user-panel">
          <div className="user-panel-info" onClick={()=>!isGuest && openProfile(myData)}>
            <div className="avatar-container"><img src={isGuest ? DEFAULT_AVATAR : (myData ? myData.photoURL : DEFAULT_AVATAR)} alt="PFP" />{!isGuest && <div className="status-dot status-online"></div>}</div>
            <div><strong>{isGuest?'Guest':(myData ? myData.displayName : 'User')}</strong></div>
          </div>
          {!isGuest ? <button className="settings-btn" onClick={openSettings} style={{color: theme}}>⚙️</button> : <button onClick={onLoginClick} style={{background:theme, padding:'6px 10px', color:'#fff', border: 'none', borderRadius: 4, cursor:'pointer'}}>Login</button>}
        </div>
      </div>

      <div className="chat-container">
        {channel ? (
          <>
            <header>
              <div style={{display:'flex', alignItems:'center'}}>
                <button className="mobile-nav-toggle" onClick={()=>setMobileNav(!mobileNav)}>☰</button>
                <div className="header-title"><span className="hash-icon">#</span> {channel.name}</div>
              </div>
              <button className="member-toggle" onClick={()=>setShowMembers(!showMembers)} style={{color: showMembers?theme:''}}>👥</button>
            </header>
            <main>
              {messages && messages.map(m => {
                const authorData = allUsers ? allUsers.find(u => u.uid === m.uid) : null;
                return <ChatMessage key={m.id} msg={m} msgRef={msgsRef.doc(m.id)} isAdmin={isAdmin} isGuest={isGuest} theme={theme} openProfile={()=>openProfile(authorData || m)} />
              })}
              <span ref={dummy}></span>
            </main>
            <div className="form-wrapper">
              {file && <div className="file-preview">{file.type==='image'?<img src={file.data} alt="prv"/>:<span>📎 {file.name}</span>}<button onClick={()=>setFile(null)}>✕</button></div>}
              {isGuest ? <div style={{background:'rgba(0,0,0,0.2)', padding:12, borderRadius:8, textAlign:'center'}}><button onClick={onLoginClick} style={{background:theme, padding:'10px 20px', color:'#fff', border:'none', borderRadius:8, cursor:'pointer'}}>Login to Send Messages</button></div> : 
              <form onSubmit={sendMsg}>
                <label className="upload-btn" style={{color: file?theme:''}}>+<input type="file" style={{display:'none'}} onChange={handleFile} /></label>
                <input type="text" value={form} onChange={e=>setForm(e.target.value)} placeholder={`Message #${channel.name}`} />
              </form>}
            </div>
          </>
        ) : <div style={{flex:1, display:'flex', justifyContent:'center', alignItems:'center'}}><h3 style={{color:'#8e9297'}}>Select a channel</h3></div>}
      </div>

      <div className={`member-list ${!showMembers ? 'hidden' : 'open'}`}>
        <div className="member-group-title">Members — {members.length}</div>
        {members.map(u => {
          const isOnline = (Date.now() - (u.lastActive||0)) < 240000;
          return (
            <div className="member-item" key={u.uid} onClick={()=>openProfile(u)}>
              <div className="avatar-container"><img src={u.photoURL||DEFAULT_AVATAR} alt="user" /><div className={`status-dot ${isOnline?'status-online':'status-offline'}`}></div></div>
              <span style={{color: u.email==='vincentr111222@gmail.com' ? '#faa61a':''}}>{u.displayName}</span>
            </div>
          )
        })}
      </div>
    </>
  )
}

